sql:
SELECT AVG(height) AS average_height
FROM players
WHERE team = 'Mia';

SELECT AVG(salary) AS average_salary
FROM players
WHERE team = 'Miami' AND draft_year = 2023;

SELECT COUNT(DISTINCT player_id) AS total_active_players
FROM players
WHERE player_status = 'active' AND games_played > 100;

SELECT full_name, games_played
FROM players
ORDER BY games_played DESC;

SELECT full_name, position
FROM players
WHERE salary = (SELECT MAX(salary) FROM players WHERE player_status = 'active');

SELECT p.full_name, s.season_year
FROM players p
INNER JOIN seasons s ON p.draft_year = s.season_year;

SELECT AVG(salary) AS average_salary
FROM players
WHERE team = 'Mia' AND games_played > 5;

external_knowledge:
- 'highest-paid active players' refers to players with a salary rank <= 5 and a status of 'active';
- 'more than a handful of games' means they have played more than 5 games;
- The average salary and salary ranks are included to provide context regarding each player's earnings relative to their peers.
